INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '超出预期的完美体验！之前看到是老牌酒店重装修，预期不高，但是入住后我没觉得有陈旧', '超出预期的完美体验！之前看到是老牌酒店重装修，预期不高，但是入住后我没觉得有陈旧感，有特色又有品质的装修风格，很惊艳，和价钱差不多的所谓快捷酒店完全两个概念。因为一点小插曲升级了套房，享受了行政酒廊，哈哈超值！一定要观赏岭南风格的花园，很美！下次来广州一定还来花园酒店！', '2024-11-28', 5, '[''整体满意度'', ''性价比'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000gx33g4u993D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000gx2y2832455_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000gx2izrc58C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234u12000gx37cv20E78_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000gx2vgfe8E2F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，白天鹅宾馆都是广州的名片，第一次到花园酒店已是三十年前啦，酒店的管理的', '花园酒店，白天鹅宾馆都是广州的名片，第一次到花园酒店已是三十年前啦，酒店的管理的一如既往，从硬件维护到服务质量都无可挑剔。', '2025-01-25', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235y12000i27ycru63E4_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231d12000i27wr8h3BD5_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233k12000i27zmhm0216_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235v12000i27tvrqC66F_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店是我在广州旅行最喜欢的酒店，非常迷人的花园环境，超一流的服务，完美的床上', '花园酒店是我在广州旅行最喜欢的酒店，非常迷人的花园环境，超一流的服务，完美的床上用品，前台优秀的较高职业素养的Kasas，以极快的速度帮我们办理入住，同时又精准的解答我的问题，还为我们升了级！温暖的笑容让我们宾至如归！早餐丰富，摆放艺术氛围拉满！祝福花园酒店！爱花园酒店', '2025-03-29', 5, '[''前台服务'', ''整体满意度'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234612000jeoua28F85E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000jep88y710B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000jep2l9d7032_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231412000jep9gjs4386_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000jeon37w1B0F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230q12000jep8my87E07_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店是老酒店了，房间的环境确实不错，吃喝玩乐都很方便，酒店大厅也是富丽堂皇，重点', '酒店是老酒店了，房间的环境确实不错，吃喝玩乐都很方便，酒店大厅也是富丽堂皇，重点来了，酒店房间的实施太老气了，还有那个电视剧小到无语。酒店里面的酒吧很棒哦！', '2024-12-25', 4, '[''房间设施'', ''周边配套'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235512000heqc41r8991_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000hepjxtpCC02_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000hepckjdC55E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000hepf3huBD89_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店位置优越，公共区域设施好??庭院设计管理很好，酒店博物馆也非常不错值得一逛?', '酒店位置优越，公共区域设施好??庭院设计管理很好，酒店博物馆也非常不错值得一逛??酒店的服务质量还是可以??不足：房间设施比较陈旧，不提供一次性马桶垫；楼下有装修白天比较闹；入住居然还要押金，太不方便了！！！', '2024-12-06', 4, '[''房间设施'', ''安静程度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000h2psebm526E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232v12000h2psoa14DE8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000h2pxv6u583D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235a12000h2pyewi7C6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232112000h2ovbzk4620_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '预订了两间房家庭亲子带老带小，到了的那天有一个特殊酒会导致前台搬了位置，办理好入', '预订了两间房家庭亲子带老带小，到了的那天有一个特殊酒会导致前台搬了位置，办理好入住没有空房需要寄存行李，被告知要自己推到礼宾处，我们三个大箱子呢，无奈自己推过去。入住时要求不要靠电梯，一上楼就是一间电梯口房间，另一件窗帘机又坏的，等了半天说给我升房了，还说要给我水果盘，但是错过了唯一一次行政酒廊的机会，后面几天都有别的安排也没时间去。
换完房就出门了，晚上回房间发现夜床也没开。不是我矫情是我真的找不到拖鞋！开了夜床就不需要自己找了。打电话问拖鞋的时候就不该多问怎么没开夜床，搞得我一包气，前台回答我是我没要求，他们酒店是要客人要求的，真是闻所未闻，那你是不是该问我下需不需要呢？
搞了半天，结果第二天早上起来其中一间房间的窗帘开关还是坏的，真的很无语。最后这次我都没和携程吐槽，真的吐槽无能了。

好了吐槽完了。酒店虽然有点年头，但是内部保养的很不错，年代感和现代化结合的非常好。酒店里的花园真的特别美，锦鲤又多又大，孩子很喜欢。
行政酒廊的HH很西式，不符合我们的中国胃，没有米饭面条，就是些面包。泳池就是港片里能看到的那种样子，露天的，淋浴也在外面。

有些遗憾没去看花园酒店博物馆，时间没安排好。但anyway，以后应该是不会再去了，这次经历属实不太愉快。', '2024-11-25', 4, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235s12000gv4om6mC725_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233l12000gv5ch8731F8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000gv4z8ksB777_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常不错的一个酒店，据说是广州本地老牌豪华酒店，地理位置好，交通便利出门就是地铁', '非常不错的一个酒店，据说是广州本地老牌豪华酒店，地理位置好，交通便利出门就是地铁，房间也不错，服务贴心，很好', '2025-02-04', 5, '[''交通便利性'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234i12000ib3n2xuC195_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000ib2ccofF502_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231q12000ib2pp6kAED4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000ib3340656F2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230912000ib2xtvy2500_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233e12000ib2viftBCAA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000ib36lkx58BF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235z12000ib2r9c51DAA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，很有调调，位置就在地铁边上，出行很方便。服务人员也都很nice，酒店还', '老牌酒店，很有调调，位置就在地铁边上，出行很方便。服务人员也都很nice，酒店还有个博物馆，可以逛逛。早餐可以在30楼旋转餐厅用餐。', '2025-01-20', 4, '[''交通便利性'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233l12000hx9b9uj4F68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000hx8h3zr5E39_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232212000hx8vava9B65_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店很有底蕴的，也很有特色，整体氛围很好。升级了房间，很宽敞，打扫也很到位。瀑布', '酒店很有底蕴的，也很有特色，整体氛围很好。升级了房间，很宽敞，打扫也很到位。瀑布餐厅自肋早餐挺好的。一次满意的体验。', '2025-01-26', 5, '[''整体满意度'', ''客房服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234u12000i343rz846E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000i3422sa0A4E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000i3357hv7CE3_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很大，睡得挺舒服的，老牌大酒店环境没得说，瀑布餐厅的早餐还不错，我们去的时候', '房间很大，睡得挺舒服的，老牌大酒店环境没得说，瀑布餐厅的早餐还不错，我们去的时候要排队，有个女的像是管理人员，说可以安排更好的餐厅吃，我们想想算了，也不赶时间就不折腾了，没想到这女的还说了句很不好听的话，素质这么低怎么当上管理职位的，其他硬件方面都不错，门口的服务员还帮忙搬行李，印象不错。', '2025-01-01', 4, '[''整体满意度'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232012000hj714sp3489_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234r12000hj7mgqd0B84_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235n12000hj6jvkl026A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000hj7bqlb0B5C_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '住店时提前订的房间没有了，说是给升级一间房，就升级了特别脏的一间房，不讲信用的一', '住店时提前订的房间没有了，说是给升级一间房，就升级了特别脏的一间房，不讲信用的一家酒店，应该是店大欺客吧', '2025-02-15', 1, '[''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0235p12000ij8g72k863E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我是住2401的客人????服务员陈红勤女土天天打扫我的房间??♀?非常干净整洁', '我是住2401的客人????服务员陈红勤女土天天打扫我的房间??♀?非常干净整洁，有求必应，态度很好??每年都住几次花园酒店、今年过年也是在花园酒店渡过。感觉非常之好啊更感谢陈红勤女士的服务??更祝?花园酒店生意越来越好！所有人开心快乐??大吉利', '2025-02-02', 5, '[''客房服务'', ''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0233p12000i8yx9zyA2CA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间环境非常好', '房间环境非常好
Mandy小姐姐耐心且专业的帮助令我和朋友印象深刻 如她们金色闪片的制服一样 提供金牌服务 专业能力十分亮眼 为她点赞??
期待下次生日也可以在花园酒店度过', '2024-12-15', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231u12000h7ym7rp1962_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000h7xwrgu2710_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000h7yn4y34B0A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000h7y4n511F28_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000h7xv6qg775F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236212000h7y063p659A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000h7ym02m18EE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很小，也比较旧，公共区域倒是不错，花园，博物馆都可以逛逛。离地铁站很近，出行', '房间很小，也比较旧，公共区域倒是不错，花园，博物馆都可以逛逛。离地铁站很近，出行方便，外国人特别多。桃园的早茶很不错', '2025-02-01', 3, '[''房间设施'', ''交通便利性'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233r12000i871ev12B50_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235v12000i88tbooADF5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000i888oij1087_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000i88dhka494D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '自从九月份住过花园的红梅套房之后，我家太上皇和小朋友都非常喜欢，这次买了三天两晚', '自从九月份住过花园的红梅套房之后，我家太上皇和小朋友都非常喜欢，这次买了三天两晚的套餐，包含行政酒廊和早餐，非常划算。行政酒廊下午茶正对着花园瀑布景色，打卡一流，有中式和西式点心，尤其是印度的Carriy主管非常nice，服务非常好，让我特别感动的是她居然还记得我们是9月来过，更是热情为我们介绍花园酒店的特色和打卡点，让老人家赞不绝口。30楼的旋转餐厅早餐和景观也特别棒。值得一住再住，尤其我们是地道广州人，情怀也很重要。', '2024-11-24', 5, '[''餐饮设施'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0233712000guk29vyD652_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000gujmabf45B8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000guju8oo6776_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000gujsa6sCD17_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000gujsalfB648_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000guk9y5aA864_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务一流，环境很好，地理位置优越，与地铁口几乎零距离，家庭亲子商务外出旅游出行都', '服务一流，环境很好，地理位置优越，与地铁口几乎零距离，家庭亲子商务外出旅游出行都很合适，性价比可以的', '2025-04-12', 4, '[''交通便利性'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230y12000jqp3bso965F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000jqoraps1DC8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235k12000jqoylbv97F6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店虽然有些年头了，但各方面都不错，位置也很好 ，出门打车坐地铁都方便，服务比较', '酒店虽然有些年头了，但各方面都不错，位置也很好 ，出门打车坐地铁都方便，服务比较到位，环境也不错，值得推荐。', '2025-02-07', 5, '[''整体满意度'', ''交通便利性'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235v12000ida73kh0E81_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000id9w1ry63AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000id9t12iF48E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '环境很好，服务超级好有求必应，设施完善，卫生很干净', '环境很好，服务超级好有求必应，设施完善，卫生很干净', '2025-03-28', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000jdejxb64618_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000jde6avoE4E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233n12000jddomvcCEBD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232b12000jdcwxbqA903_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '周边环境较好，交通便利，前厅相当不错富丽堂皇，后花园景致优美。春节有额外福利：驻', '周边环境较好，交通便利，前厅相当不错富丽堂皇，后花园景致优美。春节有额外福利：驻唱、粤剧演唱、亲子活动等。', '2025-02-01', 4, '[''周边配套'', ''交通便利性'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236212000i7vtg8x7587_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233f12000i7vtmju7336_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232u12000i7vtt4h08DB_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好，免费升级房型，服务好环境好，早餐丰富，瀑布和花园太美了，高大上，下次来广', '非常好，免费升级房型，服务好环境好，早餐丰富，瀑布和花园太美了，高大上，下次来广州还选这里！', '2025-02-11', 5, '[''整体满意度'', ''餐饮设施'', ''景观/朝向'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000igr4i2oBBA1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236e12000igqvq023CE3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230f12000igqhbzuBEFD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好，服务很热情，很有年味，一如既往的好，金卡做了升级，行政酒廊carrie 非', '很好，服务很热情，很有年味，一如既往的好，金卡做了升级，行政酒廊carrie 非常好，期待再次相遇', '2025-02-03', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/02325224x8z3ujvyt7171_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02344224x8z3ua9hrD315_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次带妈妈去旅行，选择了地理位置优越，具有岭南风格的花园酒店。妈妈真的喜欢的不行', '这次带妈妈去旅行，选择了地理位置优越，具有岭南风格的花园酒店。妈妈真的喜欢的不行！
光是酒店里的花园，我们都逛了一下午。瀑布、锦鲤、各式各样的花朵绿植，随意走到每一处都是一道靓丽的风景。
从进门到退房，妈妈都是依依不舍。酒店里的每一位工作人员给予的服务都是无微不至的！前台的Viria，听到我是带妈妈旅行，还很贴心的给妈妈送了花园酒店的花！
行政酒廊的出品也很丰富，香槟、红酒、啤酒，还有很多无酒精饮料。期间，Carrie,Berlye,Mira为我们介绍了很多菜品和酒水，妈妈第一次来真的感受到了满满的热情！说下次还要选择花园酒店！', '2024-10-02', 5, '[''整体满意度'', ''前台服务'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235x12000fx9iwyq66F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000fx9obxlFDA2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p12000fxc04xs424F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000fxaadsp14B2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000fxaumi344AE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230r12000fxakei33A14_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000fxbirux515F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000fxbca0o5A94_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000fxb4kzu50C1_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间非常干净，入住的时候前台小姐姐还给了一朵康乃馨，好温馨', '房间非常干净，入住的时候前台小姐姐还给了一朵康乃馨，好温馨', '2025-03-13', 5, '[''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000j1hc8rv2BF3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000j1hxzoc48B3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000j1g9ohsB5DD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店是知名度较高的涉外国际饭店，整体服务水平较高。位于广州老城区，寸土寸金之地内', '酒店是知名度较高的涉外国际饭店，整体服务水平较高。位于广州老城区，寸土寸金之地内部有花园散步，不错。打造了酒店博物馆，增添了文化气息。相对酒店的价格，房间浴卫盥洗区等略显局促。', '2024-12-07', 4, '[''房间设施'', ''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0233212000h3493sn01AB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232i12000h342u0w3343_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000h33qvb7C3FE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务非常好，看到带了小朋友多送了好多饮用水，还送了小甜品，打扫好房间还留了手写卡', '服务非常好，看到带了小朋友多送了好多饮用水，还送了小甜品，打扫好房间还留了手写卡片，很暖心', '2025-02-09', 5, '[''客房服务'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234312000ieync743245_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州老牌五星级酒店，但是总体各项表现还是非常出色，房间干净舒适安静，非常感谢前台', '广州老牌五星级酒店，但是总体各项表现还是非常出色，房间干净舒适安静，非常感谢前台小姐姐送的早餐，花园酒店早餐非常棒，环境也满分，儿子和女儿都很喜欢，愉快的入住体验。', '2024-12-09', 5, '[''整体满意度'', ''卫生状况'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000h4f0lsiB42D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231h12000h4f9n4v56A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234112000h4fpflk9FE0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235j12000h4fpy285895_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000h4fbjly05B6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '每次来广州都会来住一下，酒店服务一如既往的好，吃完早餐逛逛瀑布花园，时间充足的话', '每次来广州都会来住一下，酒店服务一如既往的好，吃完早餐逛逛瀑布花园，时间充足的话，还可以逛一下博物馆。', '2025-01-27', 5, '[''整体满意度'', ''餐饮设施'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233x12000i3g56ykAE25_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234712000i3h1rmo95A0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000i3ha0iyA0FB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '从机场过来地铁还是挺方便，房间不是很大，小花园景色绝佳，我们团购了一晚加早晚两餐', '从机场过来地铁还是挺方便，房间不是很大，小花园景色绝佳，我们团购了一晚加早晚两餐，还是物超所值的，以后有机会还想多住几天。', '2025-03-22', 5, '[''交通便利性'', ''景观/朝向'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0236p12000j8swdwk7960_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232512000j8tahcw1C4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230w12000j8t1y9dD0DA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '过节气氛营造到位，但房间设施确实比较老旧了，老牌星级酒店的格调还在，位置配套服务', '过节气氛营造到位，但房间设施确实比较老旧了，老牌星级酒店的格调还在，位置配套服务也都还不错，值得体验。', '2025-02-20', 3, '[''房间设施'', ''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0233o12000imxyxv07080_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000imy4mg6B1EC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000imxks3v5ADD_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一进门就闻到香喷喷的味道，酒店第二次来广州入住，酒店对面就是广州酒家，必打卡的早', '一进门就闻到香喷喷的味道，酒店第二次来广州入住，酒店对面就是广州酒家，必打卡的早茶店，值得推荐！', '2025-04-15', 5, '[''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000jt6ll51A41F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237212000jt6ezd36917_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000jt65wi6BBD2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233c12000jt6rm7w39CB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间挺好，前台Betty服务很好，住的很??意。', '房间挺好，前台Betty服务很好，住的很??意。', '2025-03-27', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234112000jckjkboADCA_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234s12000jckk2yaA500_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232u12000jckkfg3BA5E_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232g12000jckjdp03B9A_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232n12000jckjz1tF475_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230j12000jckk1p328EC_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232x12000jcklak7B6A2_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231q12000jckk4l10A23_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231t12000jckjeum54F4_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间住着很舒服，服务也不错。', '房间住着很舒服，服务也不错。
酒店地段很好，出门逛吃都很方便，春节期间酒店有很多活动，挺热闹的。', '2025-02-08', 5, '[''整体满意度'', ''周边配套'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234f12000ie38e9vEE84_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '又带家人在广州过年，这次选择在广州花园酒店，很有年味非常棒的体验！', '又带家人在广州过年，这次选择在广州花园酒店，很有年味非常棒的体验！
特别要感谢酒店的礼宾部和客房部。由于老人腿脚不便需要借用轮椅，礼宾部小李美女安排得体贴周到，让我们出行无忧游玩了很多景点，谢谢！
负责2218客房的一位男生得知老人嫌床垫软，二话不说直接把床垫翻了个面，这是事后老人对我说的，我虽未曾谋面在此表示感谢！', '2025-02-01', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0205k12000i7vihwa7383_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0232f12000i7tfojv8E87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232r12000i7ufcdz4D87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231d12000i7uklei2A66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236812000i7u23bv7FDE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230u12000i7ugzvp3C29_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233d12000i7t7n1qA661_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '初次入住花园酒店，就被酒店内圣诞的气氛吸引，非常漂亮！虽入住时遇到问题，前台很快', '初次入住花园酒店，就被酒店内圣诞的气氛吸引，非常漂亮！虽入住时遇到问题，前台很快解决了，并给我们房间升级。房间舒适宽敞，非常干净！是一次不错的体验。', '2024-12-18', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236y12000h9n8xfrCFA3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000h9n96po8101_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000h9n7z70B954_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233v12000h9n5slb33C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233r12000h9n87877B5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000h9n9phi9B67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000h9n8rb9DA82_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000h9n646h2DC5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236o12000h9n8myt0552_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店各方面完美，内部瀑布花园和博物馆非常棒！工作人员也很友善，花园酒廊的外籍女主', '酒店各方面完美，内部瀑布花园和博物馆非常棒！工作人员也很友善，花园酒廊的外籍女主管非常热情周到，总是主动问候。住店期间因为一个意外事件提出意见后，客房部侯经理及时联系沟通，并主动为我们升级了套房表示歉意，让我们感受到了酒店的用心，五星点赞??', '2025-01-06', 5, '[''整体满意度'', ''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0234h12000hmfhypjFEFB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000hme0jt48B4A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000hmer64mB7F6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000hmfipvuCEB7_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '下车后的迎宾团队做的很好，主动开车，取行李，用行李车运输大行李。 ', '下车后的迎宾团队做的很好，主动开车，取行李，用行李车运输大行李。 
前台办理入住时间很长， 行政礼遇也没有加快办理，， 没有工作人员主动引领到旁边的休息区。 后面我们自己问了一圈， 了解到旁边的沙发可以坐着等， 在旁边的沙发区等待了一个小时才拿房卡。 排队等待办理入住的人大多都有怨言，说太慢了。

定的两个大床房都很温馨， 干净， 床品质量都非常好。会有咖啡，茶水，矿泉水。喜欢提供的浴盐，但是没有提供一次性浴缸套。 针线包，丝瓜络都很好用。插座都是国际国内通用，不需要转换插头。 
小花园很美， 博物馆很不错，了解一下酒店的百年史。
早餐品类丰富， 最喜欢吃牛腩米粉。 行政走廊下午茶的点心有限， 是一些小糕点，咖啡，茶， 软饮。 晚上的行政走廊提供finger food， 对于饭量小的女士，其实也够了。 
整体来说性价比很高， 不过因为在广交会时期，酒店每天都是注满， 感觉服务上欠了点，没有达到五星酒店的松弛感。', '2024-10-24', 4, '[''前台服务'', ''退房/入住效率'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232g12000gaf824p8B29_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233212000gae2540968F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231112000gaexfvs18A6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000gaeas091404_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000gae92qrDECD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230p12000gaegaypEBE6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233412000gaeaq0n2ED2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000gaf5o15184F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233y12000gaeasea9010_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '作为广州人，每次来到花园酒店的大堂都觉得很感动，这里一直是小时候记忆里的模样，忘', '作为广州人，每次来到花园酒店的大堂都觉得很感动，这里一直是小时候记忆里的模样，忘不了第一次遇见时的惊艳。
朋友从海外回来每次都指定要住花园酒店，每次来到都见到Yannis 很亲切地打招呼，长居海外的朋友说有种回家碰到熟人的归属感。这种宾至如归的感觉也是我们选择花园的其中一个原因。', '2024-11-15', 5, '[''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234z224x8xila9jf7516_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02330224x8xilgko88CAC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232j224x8xinu2my1E67_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02367224x8xim3xqh47C5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p224x8xin1wmw74C0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236h224x8xillfqvB874_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236p224x8xim3o3iA785_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/02358224x8ximd5063798_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为花园酒店，内部环境五星，外部有施工稍显缺憾。', '不愧为花园酒店，内部环境五星，外部有施工稍显缺憾。', '2025-04-06', 4, '[''整体满意度'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230x12000jlwqpnqE93E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店，不亏是老牌广州岭南本土风情的动人酒店！装修费用具有本地风情。位置非常非', '花园酒店，不亏是老牌广州岭南本土风情的动人酒店！装修费用具有本地风情。位置非常非常好，值得体验，是动人的选择。', '2025-01-13', 5, '[''整体满意度'', ''周边配套'']', '["[ \"https://dimg04.c-ctrip.com/images/0230212000hqyj4163AA9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232c12000hqyrn8a13B7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000hqz35a32D27_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '令人惊叹，花园酒店这么老的酒店，能够维护这么好，挺神奇的，无论房间还是大堂又还是', '令人惊叹，花园酒店这么老的酒店，能够维护这么好，挺神奇的，无论房间还是大堂又还是绿化都是不会陈旧，反而更有味道，唯一需要改善的是早餐的品质需要提升', '2025-01-04', 5, '[''整体满意度'', ''房间设施'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232x12000hl3nzn24D8F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000hl3giyz4AD9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000hl38nih475B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234h12000hl3tkpq5C6E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000hl46v6189F4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000hl3w45u2ECC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233u12000hl46v639E40_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230i12000hl38nin3F06_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000hl3m8e1AA57_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '垃圾酒店 毫无性价比 房间很小 层高很低 吹风机超级没风 浴室和厕所公用一扇玻璃', '垃圾酒店 毫无性价比 房间很小 层高很低 吹风机超级没风 浴室和厕所公用一扇玻璃 浴室跟浴缸还是一体 有密闭恐惧症的千万别选它家 估计只适合日本人', '2024-12-14', 1, '[''性价比'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235n12000h7dcrfv019B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000h7cjep17231_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236s12000h7dd1rmFE0E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店装修豪华，卫生与服务一直保持高水准，我也多次入住，值得推荐。这次入住并免', '花园酒店装修豪华，卫生与服务一直保持高水准，我也多次入住，值得推荐。这次入住并免费升级了行政套房，非常享受的一次元旦假日。', '2025-01-01', 5, '[''整体满意度'', ''卫生状况'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232z12000hj3zn3iD472_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0233312000hj3zq7g880B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232512000hj3yw0i979B_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '旅行的最后一个酒店，给了非常好的体验。因为带了老人出行对房间的私密和安静程度要求', '旅行的最后一个酒店，给了非常好的体验。因为带了老人出行对房间的私密和安静程度要求有点，前台的小姐姐给了房间升级，而且正对瀑布花园景色。行政礼遇的下午茶和晚餐虽然东西不多，但是都很精致可口，好像是叫carrie外籍小姐姐吧还会不时来关心老人家的用餐体验。早餐虽然去了网红瀑布餐厅用餐，但是和行政礼遇一样偏向西式的为主。整个入住期间，每位服务人员都态度很亲切，也很有边缘感很舒服。
如果下次来广州还会住', '2024-11-04', 5, '[''前台服务'', ''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230912000ghth5oj4824_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236l12000ghsxxooB58F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000ghsvgaqD3BC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235d12000ghsq6c90997_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000ghtg7wj0BE4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '订的红棉大床房给我升级了行政套房，房间超大，很不错，服务也挺好，对小朋友也很热情', '订的红棉大床房给我升级了行政套房，房间超大，很不错，服务也挺好，对小朋友也很热情！', '2025-02-04', 5, '[''房间设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235w12000iarj03y2C98_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000iarvmgcC96E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000iarqvo0590D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好，送了行政酒廊，不愧美式酒店，很好吃！还有热情的工作人员！', '非常好，送了行政酒廊，不愧美式酒店，很好吃！还有热情的工作人员！', '2025-02-26', 5, '[''餐饮设施'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233c12000iqx5hrv2090_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000iqygzf590FB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231b12000iqytes056C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233z12000iqxmsntFA5E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '第一次来广州选择住宿花园酒店，期间得到了客服小林的帮助，对此要好好表扬和感谢。', '第一次来广州选择住宿花园酒店，期间得到了客服小林的帮助，对此要好好表扬和感谢。', '2025-03-24', 5, '[''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232o12000jaj919o42A1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000jajssno2B62_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231e12000jak2sha0604_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌酒店，有自己的博物馆，自带花园，大堂还算比较震撼！博物馆里了广州酒店的发展史', '老牌酒店，有自己的博物馆，自带花园，大堂还算比较震撼！博物馆里了广州酒店的发展史，很好', '2025-02-03', 5, '[''公共设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233w12000i9svphl96E5_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236z12000i9swev6CE13_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '瀑布餐厅早餐环境很不错，品种一般不多，酒店说线上预订房间的都不给开流水单，只能给', '瀑布餐厅早餐环境很不错，品种一般不多，酒店说线上预订房间的都不给开流水单，只能给开入住证明，第一次碰到', '2025-01-25', 4, '[''餐饮设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0236c12000i2de4d35E37_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000i2e2xdz40DE_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '一家三口，两人吃了酒店的早餐急性肠胃炎了，一个没吃的没事。谨慎选购酒店的早餐！', '一家三口，两人吃了酒店的早餐急性肠胃炎了，一个没吃的没事。谨慎选购酒店的早餐！', '2025-02-03', 3, '[''餐饮设施'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231412000ia0avad160D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这次酒店订对了，给升了房，又送了三天的行政礼遇，爸妈很满意。老爸竟然也知道这家酒', '这次酒店订对了，给升了房，又送了三天的行政礼遇，爸妈很满意。老爸竟然也知道这家酒店，说八九十年代苏州外事和这边有合作的。只是我没想到酒店的外国人含量这么高，住了三天，感觉90%是外国友人。', '2024-11-08', 5, '[''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0235j12000gki754018A0_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '迟到的评价，春节期间全家前往广州旅游，选择下榻广州花园酒店。在此，特别感谢Jen', '迟到的评价，春节期间全家前往广州旅游，选择下榻广州花园酒店。在此，特别感谢Jenis许经理，由于其中一间房间洗澡间有些渗水，帮忙将两间房的房型全部予以升级，并且还贴心安排了一间亲子房，服务专业且充满温度。广州花园酒店既有国际品牌的标准化服务，又融入岭南文化的细腻温情。为我们带来了一次极为出色的入住体验。', '2025-04-01', 5, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230612000jggtt28C8C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232w12000jghhkewF222_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000jghg4pr3F4D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231j12000jgh8nplE67B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000jghfyg26EFA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231a12000jghfpvzD268_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232t12000jghpnl18F6A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231f12000jgh54r3FC76_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234812000jghdtu45ADB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '性价比超级高！！！给我升级了更加满意哈哈哈哈', '性价比超级高！！！给我升级了更加满意哈哈哈哈', '2025-03-31', 5, '[''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232w12000jg1yz1aD8D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000jg1ov3q398E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000jg1m88pBD57_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '本来有小意外不太愉快，但前台服务态度好给升房了。套房宽敞舒适洁净，设施保养得很好', '本来有小意外不太愉快，但前台服务态度好给升房了。套房宽敞舒适洁净，设施保养得很好，酒店早餐夜茶水准也高，整体满意。', '2025-01-11', 4, '[''前台服务'', ''整体满意度'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0232c12000hq5wm7x2C1A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '花园酒店LNhotel ，历史悠久，非常大气，展现出改革开放以来的欣欣向荣, 外', '花园酒店LNhotel ，历史悠久，非常大气，展现出改革开放以来的欣欣向荣, 外国宾客占比近一半。设施齐全，室外游泳池，健身房，瑜伽馆，和米其林餐厅，行政酒廊，酒吧应有尽有。美中不足 房间内没有USB插口。
服务非常好，白金五星级的水准在线。
地理位置在越秀区，老城区。高峰时段比较拥堵。', '2024-10-30', 4, '[''公共设施'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232t12000ge3cq5s6CCC_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0236f12000ge3cn5iAE89_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0235212000ge3e5c99980_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231j12000ge3cryk8B90_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230y12000ge3cd9x700C_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232f12000ge3ck9x7A19_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234112000ge3ebkdB0A9_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州花园酒店的Echo：服务之星，温暖如家的体验', '广州花园酒店的Echo：服务之星，温暖如家的体验

在广州花园酒店，有这样一个名字，让人一提起就赞不绝口——Echo。她不仅是行政酒廊里的一道亮丽风景线，更是每一位入住宾客心中难以忘怀的温暖记忆。

Echo的服务态度，简直令人印象深刻。她以专业的知识和亲切的微笑，仿佛能瞬间化解旅途的疲惫。无论是对酒店设施的介绍，还是对周边景点的推荐，Echo总能信手拈来，让人感受到她的专业与用心。每当宾客提出需求，无论是房间的细微调整，还是餐饮的特殊要求，Echo都能迅速响应，耐心解答，确保每一位客人都能住得舒心、放心。

更难能可贵的是，Echo的细心关怀仿佛能洞察人心。她总能在不经意间，为宾客送上贴心的小惊喜，比如一杯温热的茶水，或是一份精心准备的点心。这些看似微不足道的细节，却让人感受到了家一般的温暖。', '2024-11-14', 5, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232b12000goegkat2B54_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我说呢这家酒店怎么这么灵 有种老钱有品的感觉， 一查才知道是白金五星级。 怒荐', '我说呢这家酒店怎么这么灵 有种老钱有品的感觉， 一查才知道是白金五星级。 怒荐', '2025-01-30', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231d12000i5u90ub8751_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231712000i5uq9gjB65F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000i5um9if11BB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000i5u9kmgC34A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000i5vbm8oE16C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000i5v168mA790_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '全新优美的环境不失老牌高级酒店的雍容典雅，', '全新优美的环境不失老牌高级酒店的雍容典雅，
1、前台Clarisa很贴心帮我升了房，一个姣好的微笑开启了顺利的假期
2、客房主管来电很专业的为我开好25度的恒温
3、荔湾亭帮我从前台拿来稀罕物—报纸', '2024-12-20', 5, '[''前台服务'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232512000hbc5lw6ED84_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌，一如既往的好。集住宿、美食于一体。最近荔湾亭还有晚茶自助，任食，不过可惜没', '老牌，一如既往的好。集住宿、美食于一体。最近荔湾亭还有晚茶自助，任食，不过可惜没有我最喜欢的讲估了。可能请人难??还有自助的款式里希望有濑粉。', '2025-01-10', 5, '[''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000hour83s90ED_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000hov1hh7AF46_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233a12000houxnsl36AB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '帮我升级了套房 非常惊喜', '帮我升级了套房 非常惊喜
床品毛巾都非常舒服 洗浴备品也很好用
客房服务很贴心
荔湾园早茶很好吃 住客还有75折
老牌酒店 光彩依旧', '2024-12-16', 5, '[''客房服务'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000h83pgxi255C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236f12000h84jvxp8B6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000h83l2b48A68_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000h83ec8u27CE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000h84vu2dE434_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000h84754u207A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '国庆去旅行', '国庆去旅行

房间设施:60+平方，一房一厅一卫，麻雀虽小五脏俱全，两个1.35的床，三口之家也住得很舒服。起居动线合理，有咖啡机。

性价比:国庆期间，5k不到3晚的价格相当友好。

早餐:早餐可以有四个地方选。
瀑布餐厅是传统自助，景色拍照无敌，但人较多，9点去要排队，就没进去。
顶楼旋转餐厅也是自助，人也不少，第一天没排队，第三天排了一会儿队，东西嘛，该有的都有了，就中规中矩吧，特别好吃的没有。
桃园馆是最精致的，一人一份，一个点心四小拼，一碗粥配油条，一份肠粉，一个蛋挞配水果，茶咖啡牛奶，据说不够可以加，但其实这点量我甚至吃不下！

健身房:健身房干净，器材新、全，为了可以在广州多吃点，每天都去报到1-2次

位置交通:周围挺热闹的，好吃的不少，广州酒家，利苑都是步行可达。

酒店超级大，餐厅就有四五个，还有自己的博物馆，有一个很大的后花园，酒店够老牌，有一说一，这样不计成本的排场，现在应该是很难再有了。
值得一住的酒店，有机会会再来的', '2024-12-29', 5, '[''房间设施'', ''性价比'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235k12000hh3hzhb73AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000hh3epr8E8A7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000hh3scbv3D70_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230k12000hh3oqzo7111_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235212000hh3o28y63D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232s12000hh3ueij9E87_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000hh3u45x1E1E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232312000hh3c7yuFD54_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000hh3n2p7FBDA_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '高品牌酒店，地处市中心，服务环境上乘，交通便利。还有博物馆值得参观。当然价格也有', '高品牌酒店，地处市中心，服务环境上乘，交通便利。还有博物馆值得参观。当然价格也有点偏高，性价比不够理想', '2025-01-06', 5, '[''交通便利性'', ''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232t12000hlwg44e0A23_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0232u12000hlwg44vB11B_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0230j12000hlwg18rFF4E_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '送了入住点心，房间算是宽敞舒适', '送了入住点心，房间算是宽敞舒适
洗手间是浴缸，有点不方便，而且排水较慢
bar stiller的调酒果然名不虚传去，晚上在小花园散步看星星很惬意', '2025-01-02', 4, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000hjq3jg46038_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234412000hjpql2777A2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000hjq1mio5B14_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '这家是我广州首选酒店之一，富丽堂皇的大堂给人印象深刻。从大堂门口到电梯厅及楼层一', '这家是我广州首选酒店之一，富丽堂皇的大堂给人印象深刻。从大堂门口到电梯厅及楼层一路都有服务员热情洋溢的打招呼，确实有宾至如归的感觉，特别温馨。房间设施齐全，整洁干净，床品舒适。住了好多次第一次有空去了宝藏花园，终于觉得花园酒店名副其实了。送房间的小食和水果也很精致。', '2024-10-22', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235m12000g9f427q3DB2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237312000g9fg0vw3D5A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000g9f7x2i11CD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230b12000g9f3j13D72F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231o12000g9f94vy423E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232a12000g9fhe9f3E6A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '时隔一年又来广州啦，这次依旧选了花园。体验感和去年一样棒，这次还升级成了套房。', '时隔一年又来广州啦，这次依旧选了花园。体验感和去年一样棒，这次还升级成了套房。
不过这次下午行政酒廊时发现多了不少女孩子在大镜子前拍照，还会占用卫生间，多少有些打扰住客了。', '2024-11-14', 5, '[''整体满意度'', ''公共设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236e12000gob1vm05542_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234q12000gobs3n2252A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000gobmz63E3FF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '买了关注很久po主推送的套餐，也比较优惠，就再去住一晚。最后发现，失望的多，以后', '买了关注很久po主推送的套餐，也比较优惠，就再去住一晚。最后发现，失望的多，以后没有特别情况就不会再去了。办理入住的速度很慢，这无关效率和是否人多，其实就是系统太落后了。这次选了看环市路这边的，景观也是不错，但隔音效果实在有点差，开始以为是系统隔音玻璃没问题，但归根还是之前的玻璃幕墙系统落后了。走了要登记车牌号码时，那个前台好像是欠了她钱不给的那副嘴脸，这个人估计也劝退后面不少回头客。最后车牌识别也出了问题，只有一个出口，堵着久了后面的车也不断按喇叭，打电话给一个男的来解决问题，他也是气冲冲对客户。妈呀，如果是私人酒店，首先要把这两个家伙干掉，但花园嘛，可能无所谓。不过，我更无所谓，毕竟广州还有很多的五星级酒店。', '2024-10-27', 3, '[''前台服务'', ''安静程度'', ''退房/入住效率'']', '["[ \"https://dimg04.c-ctrip.com/images/0233f12000gcd3snr3E41_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232l12000gcd9iciB524_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234x12000gcdjs939687_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237012000gcd9pnv33AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232y12000gcdce1m0EB8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236312000gcdik0045BB_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧为老牌五星级酒店，环境，卫生的说，下次还住这里', '不愧为老牌五星级酒店，环境，卫生的说，下次还住这里', '2025-02-22', 4, '[''整体满意度'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231912000io55vb43569_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233k12000io5jns67462_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '首先我要对花园酒店的工作人员表示感谢，其中包括17楼的客房服务人员，办理入住登记', '首先我要对花园酒店的工作人员表示感谢，其中包括17楼的客房服务人员，办理入住登记的Betty，以及礼宾部的工作人员，他们的服务让我看到一个五星级酒店的高水准，给人宾至如归的感受！入住当天，办理入住登记的小姑娘Betty看到我们中间有年纪大的老人，随即给我们升级了套房，借来轮椅，还送上鲜花，这样的待遇让我们充满惊喜。接下来几天，负责我们房间的客房服务人员也是认真负责，对我们的要求是有求必应，感恩，感谢。因为我们老人腿脚不便，每次出入酒店大堂，礼宾部工作人员总是特别关照，帮忙叫出租车，帮我们搬轮椅等等，谢谢你们了。除了这些员工，大堂里所见的工作人员都是对客人热情微笑，一位戴眼镜的小姐姐更是主动帮我们在大堂拍合影。酒店的硬件设施我就不赘述了，绝对的五星级感受。相比硬件设施，工作人员的礼貌、热情、乐于助人我觉得才是这个酒店最拿得出手的优势。祝你们生意兴隆！', '2025-01-04', 5, '[''前台服务'', ''客房服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232512000hl6ir7aF606_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000hl6bxstB7E8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233512000hl6p9ly48B6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000hl6t8p22B8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234y12000hl6a5mz15EE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235x12000hl6isf119CC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务到位，', '服务到位，
健身房24小时开放这个不错，
餐饮广州风味早餐晚餐丰富，
历史悠久装修风格有特色，
价格实惠???
下次来广州还会光顾', '2024-12-12', 5, '[''餐饮设施'', ''性价比'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234f224x8xzuvonoCC72_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '全国仅三，广州唯一的白金五星级酒店，服务很好，大堂很有气势，首先映入眼帘的是一幅', '全国仅三，广州唯一的白金五星级酒店，服务很好，大堂很有气势，首先映入眼帘的是一幅大型壁画，酒店一步一景，可以玩的地方很多，房间面积很大，床品舒服。', '2024-11-30', 5, '[''整体满意度'', ''房间设施'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232412000gy2b4coC818_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232m12000gy2tw1x9FA8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236i12000gy2aii163C2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232o12000gy221vi6CCB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000gy2l2in829A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234212000gy2m7hq5527_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '升级了套房，住的很舒服，酒店就在地铁站口附近，距离各个景点也近。', '升级了套房，住的很舒服，酒店就在地铁站口附近，距离各个景点也近。', '2025-02-08', 5, '[''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230v12000idy4gtm4FD6_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236512000idye67xE8FC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '很好，这次的房间能看到一点小蛮腰。酒店交通方便，本身自带几家米其林，旁边还有利苑', '很好，这次的房间能看到一点小蛮腰。酒店交通方便，本身自带几家米其林，旁边还有利苑。各方面都很棒，唯一略有不足是房间插座少了些，如果能有智能马桶就更棒啦。期待下次再入住', '2024-10-08', 5, '[''景观/朝向'', ''交通便利性'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0231z12000g1hyitmBA9B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233o12000g1i6eu7FB7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232012000g1i3ihm9E18_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0237412000g1i7pti011E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232x12000g1hupdo0D6B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235r12000g1htnekC090_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233612000g1i48bf005B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000g1hoziy3FCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236r12000g1i841r6504_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务好，入住和退房、退押金都很快。餐厅服务人员态度和蔼热情，帮助送餐到位。', '服务好，入住和退房、退押金都很快。餐厅服务人员态度和蔼热情，帮助送餐到位。
酒店环境很好，能够享受行政酒廊待遇让我们很惊喜。', '2024-12-01', 4, '[''前台服务'', ''退房/入住效率'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0204412000gyvxfvbCA70_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0233912000gyvqrj6D2C8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230d12000gyv1j847B32_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000gyvjrv1E3D0_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234912000gyvsxma6AD3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235h12000gyvq22d6A55_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230v12000gyv4tpa4B9C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000gyvfd5y4EEA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000gyv2fz6C6D8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000gyvfd60A85B_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间比较宽敞，40年老酒店维护还不错，21楼视野很开阔。洗手间拉门设计感觉不方便', '房间比较宽敞，40年老酒店维护还不错，21楼视野很开阔。洗手间拉门设计感觉不方便，穿衣镜对着淋浴房会尴尬。房门把手开门要向上，一开始没反应过来，还好客房服务员主动打招呼过来帮忙说明。公共区域环境非常赞，大堂富丽堂皇，酒店博物馆，花园和瀑布非常漂亮。交通特别方便，地铁5号线淘金站就在边上，去哪里都方便。附近很多美食，对面广州酒家，不远就是利苑，北园也很近。一楼瀑布餐厅早餐比较丰富，推荐竹升面配萝卜牛腩。30楼旋转餐厅有点晕，品种比一楼少，但是也够了，现煮面条配红烧牛腩很赞。', '2024-10-06', 4, '[''周边配套'', ''交通便利性'', ''公共设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0233h12000g0jo3f5B58B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232p12000g0jjw722279_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230y12000g0jjbkn2F5E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000g0jln2uC106_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232612000g0j3z9f6465_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234a12000g0jfhm1D8AF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000g0jlv0w3B5F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230l12000g0jb9khF236_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236b12000g0jm8h7C385_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店非常值得住，高档国际酒店，还给我一个惊喜！升级住房', '酒店非常值得住，高档国际酒店，还给我一个惊喜！升级住房', '2025-02-15', 5, '[''整体满意度'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0230412000ijow8cyAE33_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230812000ijod8bkDA0C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231y12000ijo9hqcD5FF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230n12000ijoisnm2B7D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '我们到达正好赶上广交会，入住的人比较多', '我们到达正好赶上广交会，入住的人比较多

设施：设施很完善，附近也很便利

卫生：干净整洁
唯一就是这家酒店是没有外卖小车的，无法将外卖送到楼上，需要住客自己下楼取外卖，介意的宝子们注意哦～', '2024-10-28', 5, '[''周边配套'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0236g12000gcq9joxBBDF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234i12000gcqcai28AE2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231612000gcqjwjwC523_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '服务态度热情周到细致?? 客房布局合理??', '服务态度热情周到细致?? 客房布局合理??
设施齐全配套完善??
卫生整洁优美??
环境优雅舒适??非常完美的一次旅行体验??', '2024-12-19', 5, '[''整体满意度'', ''前台服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0230i12000hagku3dD756_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000hagh8xu717B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233f12000hagb07w08E1_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000hahiy5c8EBD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236q12000hagkvma3EF4_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '反映了床垫有点软，马上便有服务员来换了，服务超赞。前台搞待员Cecilia美丽且', '反映了床垫有点软，马上便有服务员来换了，服务超赞。前台搞待员Cecilia美丽且态度很好，使人感到很舒服，谢谢。入住期间遇到的酒店的所有员工都非常有礼貌。超赞。', '2025-01-28', 4, '[''客房服务'', ''前台服务'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0231b12000i42owh1BAA7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230g12000i42yroiB1D6_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '景色如酒店的名字 像一个巨大的花园', '景色如酒店的名字 像一个巨大的花园
优质的服务 让人宾至如归', '2025-02-05', 5, '[''景观/朝向'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000iblwrw45811_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店装修融合了中国传统文化和岭南园林风情，有非常多的艺术品，如同走进一座充满艺术', '酒店装修融合了中国传统文化和岭南园林风情，有非常多的艺术品，如同走进一座充满艺术气息的殿堂。贴心服务，无微细致.', '2024-12-19', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232e324x8y38oiq12C6D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好，服务态度很好，房间很干净很大，带妈妈过去过生日，酒店帮忙布置了，送了蛋糕', '非常好，服务态度很好，房间很干净很大，带妈妈过去过生日，酒店帮忙布置了，送了蛋糕，很满意～^_^^_^^_^^_^^_^^_^', '2025-01-29', 5, '[''整体满意度'', ''客房服务'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0231n12000i591f0oE039_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235m12000i589mfy7048_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234p12000i59n4ppB92D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232u12000i5a2ju176D2_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间太细，也有年代感了，冲凉房设计不好，要踏进去比较困难。大堂很漂亮，早餐也很好', '房间太细，也有年代感了，冲凉房设计不好，要踏进去比较困难。大堂很漂亮，早餐也很好。打卡拍照超好看，值得住的。', '2024-12-27', 4, '[''房间设施'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230q12000hfucyxc5785_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235w12000hfu0x151D1A_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233p12000hfu2qqx0673_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店地理位置极佳，挨着淘金站地铁口，大堂门口也常有空出租车在等客人。卫生方面其实', '酒店地理位置极佳，挨着淘金站地铁口，大堂门口也常有空出租车在等客人。卫生方面其实挺好的，就是刚进房的时候发现有前面客人遗留的依云水标签没收走，其他地方都很干净。设施方面，房间衣柜表面有明显的木头老化痕迹，床很高偏软但不会太塌，洗手间水力够大，水压水温都稳。房间装饰挺不错的，但是靠门口的墙上有红字印子。窗对着正门花坛和外面的主干道，但是不吵，窗户隔音到位，不过如果有人在走廊上说话或者邻居的关门声还是能从门传进来。', '2024-09-02', 4, '[''交通便利性'', ''房间设施'', ''安静程度'']', '["[ \"https://dimg04.c-ctrip.com/images/0230i12000fcmn3m8BAD2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233h12000fcm9s49914F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230212000fcmnm1c50B9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235612000fcmebhh4B36_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235l12000fcmd9p39A92_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231w12000fcmob5f7AE4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236412000fcmi7es0220_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000fcmdo1t3AB4_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230112000fcmobwc9207_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '浓浓老钱风的花园酒店，是黄佟佟小姐推荐的，果然不负所望??', '浓浓老钱风的花园酒店，是黄佟佟小姐推荐的，果然不负所望??', '2025-04-18', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0236m12000jwtyhrk211B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230s12000jwul3mjF6FE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230x12000jwuqt0cA32E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间不错，过年氛围很浓，还有各种演出，出门就是地铁口，交通方便。', '房间不错，过年氛围很浓，还有各种演出，出门就是地铁口，交通方便。', '2025-02-03', 5, '[''交通便利性'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233212000i9vq1xf0415_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '入住顺利，帮我们升级了行政套房，房间很大，还配备了瑜伽垫，服务周到。卫生间的各项', '入住顺利，帮我们升级了行政套房，房间很大，还配备了瑜伽垫，服务周到。卫生间的各项设施完备，餐厅的早餐也不错。不足的地方在于，房间里的电视不能联网。', '2024-11-18', 5, '[''房间设施'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230k12000gqic03y1408_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234k12000gqiu8eqBC27_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231k12000gqiov2f603C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232712000gqir7sw9631_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231p12000gqhtdol6C9D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230j12000gqikif7EF0F_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间很好，免费升级了房型，服务周到，环境也很好，非常满意！！！', '房间很好，免费升级了房型，服务周到，环境也很好，非常满意！！！', '2025-01-29', 5, '[''整体满意度'', ''前台服务'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234n12000i4sbwcb112D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230712000i4salpbEDCE_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230312000i4st6eqAFEC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '老牌的五星酒店，携程买的套餐价格还挺划算的。入住送了欢迎小点心，甚至第二天玩回来', '老牌的五星酒店，携程买的套餐价格还挺划算的。入住送了欢迎小点心，甚至第二天玩回来居然准备了一个生日蛋糕，真是意外。整体工作人员的服务很好，搞得我都有点不好意思。
行政酒廊附赠的早餐比较一般了，下午茶还行，一楼花园很好拍有瀑布适合拍照。
老式的五星级酒店，房间会有一点点潮湿味道的感觉，然后淋浴房和厕所的推移门有点卡顿，房间的浴缸摆放位置会有点影响动线。然后没有共享洗衣房，可能住这个酒店的不需要这个吧哈哈哈哈', '2024-10-10', 4, '[''房间设施'', ''前台服务'', ''性价比'']', '["[ \"https://dimg04.c-ctrip.com/images/0234y12000g2j5qhz600E_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233q12000g2j1xyb82AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234m12000g2j1xyd83E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231n12000g2j3mxu3F99_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间老旧，墙壁发霉，很潮湿。', '房间老旧，墙壁发霉，很潮湿。
服务质量没发上传照片，广州首批五星酒店服务态度领教了，分享一下我的体验大家参考吧。
带小孩办理入住，问能否加婴儿床？
不行，65平的房间才可以加婴儿床。
办理的时候想问问有没有已经收拾好的房间？
没有，而且我们这里入住时间是2点。
通常不是留个联系方式，有打扫出来的房间，我们会电话通知您吗？？？
没事，寄存行李，然后出去逛一圈，2点之后回来领房卡，电脑一顿敲，然后就只说先生办好了。卡也没给，房号也没告诉，整个过程早餐在哪，行政酒廊在哪，什么都没告知，两位前台整个过程没一点微笑。
其他酒店通常都是想办法帮助客人，而不是给人一种高冷的态度，与前两天住Langham相比，不管是服务，设施，早餐或是酒廊，差得不只一点，这样的花园酒店还配五星？
对了 happy hour酒水就只有gin and tonic和JackDaniel with coke两种...
整体不推荐尝试这家老牌五星级酒店', '2024-10-09', 0, '[''前台服务'', ''房间设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0235q12000g29f06rA9F9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232q12000g293h97205E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '非常好，去哪里都比较方便 。', '非常好，去哪里都比较方便 。
格外喜欢大堂
服务也很好 ，行政酒廊的Carrie 真的很Nice', '2024-12-29', 5, '[''交通便利性'', ''前台服务'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234v12000hh7si4o1E79_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232e12000hh7u0rp93D2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235q12000hh7jc7b7334_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236m12000hh7jc7d9EEF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '中秋来广州之前定了能看到广州塔的宾馆，但是考虑到大部分景点和美食都在越秀和荔湾，', '中秋来广州之前定了能看到广州塔的宾馆，但是考虑到大部分景点和美食都在越秀和荔湾，最后一刻改回了花园酒店。网上差评不少，因为酒店年头太久了，说房间种种不好，本来心中非常忐忑，但是在踏进大堂的一瞬间就觉得来对了。不同于传统连锁五星的模式化设计，富有岭南特色的大堂气派非凡，节假日虽然房间内没有升级但也非常精致。酒店设施齐全服务热情体贴，钻石会员升级了行政礼遇，赠送了30楼旋转餐厅的早餐，还有下午茶和happy hour，可以广东的美食太多了，根本没有那么多胃口一一品尝。酒店花园小巧精致，人工瀑布，小桥流水，锦鲤往来，酒店博物馆诉说了悠久的历史和文化，总结来说放心来住，非常好??', '2024-09-17', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0236b12000flwx1u6009D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234e12000flx5mgp4B66_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231212000flwjktcCB16_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233t12000flwxispF733_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000flwr1vfAFCF_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236g12000flwyn1vE915_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235812000flx7qd7BB1F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235f12000flwr1vh9A7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230412000flwx1u870BC_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '在广州永远的第一选择，宾至如归。酒店位置优越，交通便利。设施齐全，床铺柔软，视野', '在广州永远的第一选择，宾至如归。酒店位置优越，交通便利。设施齐全，床铺柔软，视野良好。餐饮出色，美食多样且美味。工作人员热情友好、专业高效，服务周到。', '2024-11-11', 5, '[''整体满意度'', ''交通便利性'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0235e12000gm98ovs39F6_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0234z12000gm935vw25BC_R_150_150_R5_Q70_D.png\", \"https://dimg04.c-ctrip.com/images/0231a12000gm96eomFB4F_R_150_150_R5_Q70_D.png\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '酒店真的超级棒，推荐入住，酒店在十一长假中还帮我升级了房间，和父母住了超大的套房', '酒店真的超级棒，推荐入住，酒店在十一长假中还帮我升级了房间，和父母住了超大的套房，酒店有自己的花园、瀑布餐厅、层顶泳池、博物馆，大厅的超大大观园漆面描金画真的很生动，木雕楼梯也很绝。就是超五星的配置。', '2024-10-07', 5, '[''整体满意度'', ''公共设施'', ''房间设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0230u12000g11amihEC8B_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000g11b9ya6772_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '地理位置不错，出门就是地铁站，步行沿淘金路去了韵姐糖水，挺好吃的，值得尝试，当然', '地理位置不错，出门就是地铁站，步行沿淘金路去了韵姐糖水，挺好吃的，值得尝试，当然你也可以点外卖。房间有免费的咖啡胶囊，还有小瓶漱口水，这点我觉得很棒。酒店的博物馆也很值得参观，蛮大的，东西也多。
瀑布餐厅也就那样吧，可能是水气的原因，玻璃感觉脏脏的，糊糊的，观感大打折扣。早茶种类较少，没有特点也没啥亮点，就牛肉烧卖和蔬菜蒸饺有点好吃，所以不值得买带早餐的房间我觉得。
房间空调关了还是冷，服务员提供了暖风机，但开着很吵，不过阿姨很热情笑脸相迎。
我觉得床太软了而且没弹性非常不舒服，一晚上没睡好，另外床单上有两处碎头发，洗脸池有上个客人粘在上面的鼻屎。尽管房间的装修风格我很喜欢，但以后应该不会再入住了。', '2024-10-05', 3, '[''房间设施'', ''交通便利性'', ''卫生状况'']', '["[ \"https://dimg04.c-ctrip.com/images/0234812000fzxcvjt5BB8_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235u12000fzx37jk3393_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '房间干净，环境很好，服务态度满意，早餐品种丰富，午茶好喝又休闲，晚餐虽然品种少了', '房间干净，环境很好，服务态度满意，早餐品种丰富，午茶好喝又休闲，晚餐虽然品种少了点，但高端上挡次，不愧为花园一样的酒店。', '2024-12-04', 5, '[''卫生状况'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0232v12000h15ktsc5C82_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234312000h15bb6jDCBC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234f12000h15j7jv287A_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '选择入住花园酒店作为此次广州旅行的第一站，花园酒店是我国唯三家的白金五星酒店，也', '选择入住花园酒店作为此次广州旅行的第一站，花园酒店是我国唯三家的白金五星酒店，也是亚运会的接待酒店，非常磅礴经典大气，妈妈第一眼就爱上了，映入眼帘的黑金配色的大观园，黑白配色经典的瀑布餐厅，后花园的超级大的鲤鱼都给这次旅行注入新鲜活力。

花园博物馆是一大特色，里面记录了我国酒店发展的故事，花园酒店里面设施的用心，非常推荐。这是第二次入住花园酒店了，应该会有第三次？', '2024-10-06', 5, '[''整体满意度'', ''公共设施'', ''餐饮设施'']', '["[ \"https://dimg04.c-ctrip.com/images/0234p12000g04stvv153F_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234j12000g04oqdc0441_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235912000g04m8f01C2E_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '种草了很久的酒店，这次终于住上了，硬件非常好', '种草了很久的酒店，这次终于住上了，硬件非常好
其实设施和大多数五星级酒店差不多，亮点在花园和博物馆，花园植物非常丰富，我们参加活动找10种指定植物很有意义，瀑布拍照??很美丽。博物馆在四层，展品丰富。
酒店附近711，点都德，地铁都超级近
我们住了两天，房间打扫很及时，整洁如新
槽点在前台，第一天入住居然要排队，大家在大厅罚站，倒水喝根本解决不了问题，不如搞些pad也做入住。早饭也是排队。一个问题问好几个服务人员才行。和客人交流不说您好……最后想晚一些退房，前台穿金片衣服的小姐姐直接要好评，还要我展示给她看，五星级还要这样刷好评吗？', '2024-10-07', 4, '[''前台服务'', ''周边配套'', ''客房服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0233u12000g0x4d039CEC_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0235512000g0x5qzgBB17_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '广州的老牌五星酒店，这个价格是真的超值了，城市中的后花园，早餐口味比较偏向西式和', '广州的老牌五星酒店，这个价格是真的超值了，城市中的后花园，早餐口味比较偏向西式和中东，中式选择不多，这也能理解的，毕竟这里西方和中东客人比较多。', '2024-11-12', 5, '[''性价比'', ''餐饮设施'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0233z12000gn3407f9BAD_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231512000gn26oy7CE7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234v12000gn3407h6E58_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0230612000gn2sv3797DF_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '确实是老牌酒店，金碧辉煌，如果在30年前一定是顶流', '确实是老牌酒店，金碧辉煌，如果在30年前一定是顶流', '2025-02-05', 5, '[''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0234q12000ibm5r0f2AB7_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233312000ibm0z7c3127_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231m12000iblpc2c5285_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232d12000ibli0pj7F9D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '之前看评论说酒店旧，可是冲着老牌酒店的名声还是去决定试试，结果超预期。酒店房间还', '之前看评论说酒店旧，可是冲着老牌酒店的名声还是去决定试试，结果超预期。酒店房间还带一客厅，等于是套房，房间也挺新的，房间两个洗手台，厕所干湿分离很不错。提前告知孩子生日还把房间布置了，送了一个小蛋糕。酒店后花园也很漂亮，还有后花园和四楼博物馆打卡活动，孩子玩的很开心，下次还会选择入住，老牌五星酒店还是有他的底蕴在的', '2024-10-04', 4, '[''房间设施'', ''整体满意度'', ''前台服务'']', '["[ \"https://dimg04.c-ctrip.com/images/0232512000fz502fy7A4C_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231012000fz5up7vAA97_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236w12000fz52xewBFC9_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233x12000fz502g273C3_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0233w12000fz5165l96EB_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0236c12000fz5mwcg8A7D_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232912000fz42nfaFAF2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0232412000fz4n3yw356D_R_150_150_R5_Q70_D.jpg\" ]"]'); INSERT INTO comments (hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category, images) VALUES ('未知酒店', '未知地点', '匿名', '不愧是白金级五星酒店，大堂的布置既富贵又有文化，特别是两幅壁画，叹为观止。酒店的', '不愧是白金级五星酒店，大堂的布置既富贵又有文化，特别是两幅壁画，叹为观止。酒店的博物馆很值得一看，了解到中西酒店的发展历史和酒店文化。酒店地理位置好，在地铁边，交通方便。对面就是广州酒家和友谊商店。酒店房间不大，但设计精巧，类似国外酒店。后花园有高，低两个瀑布，人少景美，很喜欢这家酒店！', '2024-10-08', 5, '[''交通便利性'', ''周边配套'', ''整体满意度'']', '["[ \"https://dimg04.c-ctrip.com/images/0200e12000g1j7o9851B0_W_350_350_R5_Q70.jpg?proc=autoorient\", \"https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png\", \"https://dimg04.c-ctrip.com/images/0234d12000g1isd27C0AA_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0231x12000g1ivfk4F4E2_R_150_150_R5_Q70_D.jpg\", \"https://dimg04.c-ctrip.com/images/0234s12000g1iva0a745B_R_150_150_R5_Q70_D.jpg\" ]"]');